    {"repo_name": "repo1"}, {"repo_name": "repo2"}
]
# Direct query to get apache repos  
apache_repos = [
    {"repo_name": "repo2"}, {"repo_name": "repo3"}
]

shell_names = {r['repo_name'] for r in shell_repos}
apache_names = {r['repo_name'] for r in apache_repos}
